import{_ as a,o as e,c as t,ah as i}from"./chunks/framework.ojwJKwrc.js";const u=JSON.parse('{"title":"Combinational Loops","description":"","frontmatter":{},"headers":[],"relativePath":"guide/combinational-loops.md","filePath":"guide/combinational-loops.md"}'),n={name:"guide/combinational-loops.md"};function o(l,s,p,d,h,r){return e(),t("div",null,[...s[0]||(s[0]=[i(`<h1 id="combinational-loops" tabindex="-1">Combinational Loops <a class="header-anchor" href="#combinational-loops" aria-label="Permalink to &quot;Combinational Loops&quot;">​</a></h1><p>Celox performs static dependency analysis on <code>always_comb</code> blocks and schedules them in topological order. When it detects a cycle in the dependency graph, compilation fails with a <code>CombinationalLoop</code> error.</p><p>There are two distinct situations that produce this error, and each has its own fix.</p><h2 id="false-loops" tabindex="-1">False Loops <a class="header-anchor" href="#false-loops" aria-label="Permalink to &quot;False Loops&quot;">​</a></h2><p>A <strong>false loop</strong> is a cycle that appears in the static dependency graph but can never actually loop at runtime. The most common cause is a mux whose two branches each depend on the opposite path:</p><div class="language-veryl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">veryl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>module Top (</span></span>
<span class="line"><span>    sel: input  logic,</span></span>
<span class="line"><span>    i:   input  logic&lt;2&gt;,</span></span>
<span class="line"><span>    o:   output logic&lt;2&gt;,</span></span>
<span class="line"><span>) {</span></span>
<span class="line"><span>    var v: logic&lt;2&gt;;</span></span>
<span class="line"><span>    always_comb {</span></span>
<span class="line"><span>        if sel {</span></span>
<span class="line"><span>            v[0] = v[1];  // reads v[1]</span></span>
<span class="line"><span>            v[1] = i[1];</span></span>
<span class="line"><span>        } else {</span></span>
<span class="line"><span>            v[0] = i[0];</span></span>
<span class="line"><span>            v[1] = v[0];  // reads v[0]</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    assign o = v;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><code>v[0]</code> and <code>v[1]</code> appear to depend on each other, but <code>v[0]→v[1]</code> only happens when <code>sel=1</code> and <code>v[1]→v[0]</code> only when <code>sel=0</code> — they never loop simultaneously.</p><p>Without intervention, this fails to compile. Use <code>falseLoops</code> to declare the cycle safe:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> sim</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Simulator.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fromSource</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">SOURCE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Top&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  falseLoops: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    { from: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;v&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, to: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;v&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">});</span></span></code></pre></div><p>The <code>from</code> and <code>to</code> fields identify the signals involved in the cycle. Celox will execute the SCC block multiple times (the exact count is derived from the structural depth of the cycle) to ensure all values propagate correctly regardless of execution order.</p><h2 id="true-loops" tabindex="-1">True Loops <a class="header-anchor" href="#true-loops" aria-label="Permalink to &quot;True Loops&quot;">​</a></h2><p>A <strong>true loop</strong> is a genuine combinational feedback path — the output feeds back into the input and the circuit must iterate until it reaches a stable state (fixed point).</p><div class="language-veryl vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">veryl</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>module Top (i: input logic, o: output logic&lt;4&gt;) {</span></span>
<span class="line"><span>    var v: logic&lt;4&gt;;</span></span>
<span class="line"><span>    always_comb {</span></span>
<span class="line"><span>        v = {v[2:0], i};  // shift register: feeds back into itself</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    assign o = v;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>By default, Celox allows only a small number of iterations (based on the structural loop depth). If the circuit needs more iterations to converge, declare a <code>trueLoop</code> with a sufficient <code>maxIter</code>:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> sim</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Simulator.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fromSource</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">SOURCE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Top&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  trueLoops: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    { from: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;v&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, to: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;v&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, maxIter: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">});</span></span></code></pre></div><p>If the loop does not converge within <code>maxIter</code> iterations, the simulation throws a <code>DetectedTrueLoop</code> error at runtime.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>A true loop that never converges (e.g., <code>assign y = ~y</code>) will always throw at runtime regardless of <code>maxIter</code>. This represents combinational oscillation, which is not a valid hardware state.</p></div><h2 id="signal-path-syntax" tabindex="-1">Signal Path Syntax <a class="header-anchor" href="#signal-path-syntax" aria-label="Permalink to &quot;Signal Path Syntax&quot;">​</a></h2><p>Both <code>from</code> and <code>to</code> accept a signal path string:</p><table tabindex="0"><thead><tr><th>Pattern</th><th>Meaning</th></tr></thead><tbody><tr><td><code>&quot;v&quot;</code></td><td>Top-level variable <code>v</code></td></tr><tr><td><code>&quot;u_sub:i_data&quot;</code></td><td>Port <code>i_data</code> of child instance <code>u_sub</code></td></tr><tr><td><code>&quot;u_a.u_b:x&quot;</code></td><td>Port <code>x</code> of instance <code>u_b</code> inside <code>u_a</code></td></tr></tbody></table><h2 id="choosing-between-falseloops-and-trueloops" tabindex="-1">Choosing Between falseLoops and trueLoops <a class="header-anchor" href="#choosing-between-falseloops-and-trueloops" aria-label="Permalink to &quot;Choosing Between falseLoops and trueLoops&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th><code>falseLoops</code></th><th><code>trueLoops</code></th></tr></thead><tbody><tr><td>Cycle is real at runtime</td><td>No — paths are mutually exclusive</td><td>Yes — output feeds back to input</td></tr><tr><td>Iteration behavior</td><td>Statically unrolled N times (N = structural depth)</td><td>Iterates until convergence or <code>maxIter</code></td></tr><tr><td>Runtime error possible</td><td>No</td><td>Yes, if it fails to converge</td></tr></tbody></table><h2 id="further-reading" tabindex="-1">Further Reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further Reading&quot;">​</a></h2><ul><li><a href="/celox/internals/combinational-analysis.html">Combinational Analysis</a> -- How the dependency graph is built and scheduled.</li><li><a href="./writing-tests.html">Writing Tests</a> -- Simulator options overview.</li></ul>`,24)])])}const k=a(n,[["render",o]]);export{u as __pageData,k as default};
